// Get all news items
const items = $input.all();

// Get current date
const today = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Build HTML email
let html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto; padding: 20px; }
    h1 { color: #2c3e50; border-bottom: 3px solid #3498db; padding-bottom: 10px; }
    .date { color: #7f8c8d; font-size: 14px; margin-bottom: 20px; }
    .news-item { margin-bottom: 25px; padding: 15px; background: #f8f9fa; border-left: 4px solid #3498db; }
    .news-item h2 { margin: 0 0 10px 0; font-size: 18px; color: #2c3e50; }
    .news-item p { margin: 0 0 10px 0; color: #555; }
    .news-item a { color: #3498db; text-decoration: none; font-weight: bold; }
    .news-item a:hover { text-decoration: underline; }
    .footer { margin-top: 30px; padding-top: 20px; border-top: 1px solid #ddd; text-align: center; color: #7f8c8d; font-size: 12px; }
  </style>
</head>
<body>
  <h1>📢 Daily News Update</h1>
  <div class="date">📅 ${today}</div>
`;

// Add each news item
items.forEach((item, index) => {
  const title = item.json.title || 'No Title';
  const description = item.json.contentSnippet || item.json.description || 'No description available';
  const link = item.json.link || '#';

  html += `
  <div class="news-item">
    <h2>${index + 1}. ${title}</h2>
    <p>${description}</p>
    <a href="${link}" target="_blank">Read more →</a>
  </div>
  `;
});

// Close HTML
html += `
  <div class="footer">
    <p>🤖 This email was automatically generated by your n8n workflow</p>
    <p>You're receiving this daily news digest at your request</p>
  </div>
</body>
</html>
`;

// Return the formatted HTML
return [{ json: { html, subject: `📢 Daily News Update - ${today}` } }];
